svg.script:
	function flipVisibilityC(evt,clid) {
		var svgdoc = evt.getTarget().getOwnerDocument();
		flipVisibility(svgdoc.getElementById(clid + "EU"));
		flipVisibility(svgdoc.getElementById(clid + "AS"));
		flipVisibility(svgdoc.getElementById(clid + "US"));
	}
    function flipVisibility(group) {
    	var vis = group.getAttribute("visibility");
    	if (vis == "inherit") { 
    	   group.setAttribute("visibility","hidden")
    	} else {
    	   group.setAttribute("visibility","inherit")
    	}
    }
    function postitOn(evt,onoff) {
        var node   = evt.getTarget();
        var svgdoc = node.getOwnerDocument();
        var name   = node.getAttribute("ivan:id")
        var postit = svgdoc.getElementById(name)
        if (onoff == "on") {
          cx = node.getAttribute("cx")
          x = parseInt(cx) + 30;
          if ( x + 400 >= 1100 ) {
              x = x - 400;
          }
          cy = node.getAttribute("cy")
          y = parseInt(cy) + 60;
          trans = "translate(" + x + " " + y + ")"
          postit.setAttribute("transform",trans)
          postit.setAttribute("visibility","visible")
        } else {
          postit.setAttribute("visibility","hidden")
        }
    }
